define i32 @OrSelectIcmpNonZero(i32 %a, i32 %b) {
  %cmp = icmp eq i32 %a, 0
  %sel = select i1 %cmp, i32 %b, i32 42
  %or = or i32 %sel, %a
  ret i32 %or
}

define i32 @OrSelectIcmpZero(i32 %a, i32 %b) {
  %cmp = icmp eq i32 %a, 0
  %sel = select i1 %cmp, i32 %b, i32 0
  %or = or i32 %sel, %a
  ret i32 %or
}

define i32 @OrSelectIcmpZeroCommuted(i32 %a, i32 %b) {
  %cmp = icmp eq i32 %a, 0
  %sel = select i1 %cmp, i32 %b, i32 0
  %or = or i32 %a, %sel
  ret i32 %or
